import React, { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Search } from 'lucide-react';
import MealCard from '../components/MealCard';
import { getMeals } from '../api/services';

// Example local images (put your images in src/assets and import them)
import nonvegbf from '../assets/N.jpeg';
import quinoaImg from '../assets/quinoa.jpg';      // <-- add your file
import pancakeImg from '../assets/pancake.jpg';   // <-- add your file

const Menu = () => {
  const [meals, setMeals] = useState([]);
  const [filteredMeals, setFilteredMeals] = useState([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('All');
  const [loading, setLoading] = useState(true);

  // Keep category labels user-facing (buttons)
  const categories = [
    'All',
    'High Protein',
    'Salads',
    'Fruit Bowl',
    'Protein Shakes',
    'Keto Meal',
    'Low-cal rice bowls'
  ];

  // Mock meal data: set `image` to either an imported variable (local image)
  // or a public URL. For public folder images use "/images/yourfile.jpg"
  const mockMeals = [
    {
      id: 1,
      name: 'Non-veg Breakfast',
      description: 'High protein-packed breakfast',
      image: nonvegbf, // <-- use imported image variable
      price: 79,
      protein: 35,
      carbs: 43.5,
      fiber: 8.5,
      calories: 674,
      category: 'High Protein',
    },
    {
      id: 2,
      name: 'Quinoa Buddha Bowl',
      description: 'Vegan superfood bowl',
      // This example uses a local import (quinoaImg). You can also use a URL string:
      // image: 'https://images.unsplash.com/....'
      image: quinoaImg,
      price: 249,
      protein: 12,
      carbs: 45,
      fiber: 8,
      calories: 320,
      category: 'Keto Meal',
    },
    {
      id: 3,
      name: 'Egg White Omelet',
      description: 'Perfect breakfast choice',
      // Example using an external URL
      image: 'https://images.unsplash.com/photo-1585238341710-4b4e6784d0e0?w=500&h=400&fit=crop',
      price: 199,
      protein: 28,
      carbs: 8,
      fiber: 2,
      calories: 220,
      category: 'Salads',
    },
    {
      id: 4,
      name: 'Salmon Fillet',
      description: 'Omega-3 rich protein',
      image: '/images/salmon.jpg', // <-- example if you put salmon.jpg in public/images/
      price: 399,
      protein: 42,
      carbs: 0,
      fiber: 0,
      calories: 280,
      category: 'High Protein',
    },
    {
      id: 5,
      name: 'Vegetable Stir Fry',
      description: 'Low carb veggie delight',
      image: 'https://images.unsplash.com/photo-1609501676725-7186f017a4b0?w=500&h=400&fit=crop',
      price: 229,
      protein: 8,
      carbs: 18,
      fiber: 6,
      calories: 180,
      category: 'Low-cal rice bowls',
    },
    {
      id: 6,
      name: 'Protein Pancakes',
      description: 'High protein breakfast',
      image: pancakeImg,
      price: 189,
      protein: 35,
      carbs: 32,
      fiber: 4,
      calories: 380,
      category: 'Keto Meal',
    },
    {
      id: 7,
      name: 'Grilled Tofu Wrap',
      description: 'Vegan protein wrap',
      image: 'https://images.unsplash.com/photo-1565299585323-38d6b0865b47?w=500&h=400&fit=crop',
      price: 219,
      protein: 18,
      carbs: 35,
      fiber: 7,
      calories: 310,
      category: 'Keto Meal',
    },
    {
      id: 8,
      name: 'Chicken Salad',
      description: 'Fresh and healthy lunch',
      image: 'https://images.unsplash.com/photo-1540189549336-e6e99c3679fe?w=500&h=400&fit=crop',
      price: 279,
      protein: 38,
      carbs: 12,
      fiber: 5,
      calories: 290,
      category: 'Salads',
    },
    {
      id: 9,
      name: 'Protein Bars',
      description: 'Quick snack option',
      image: 'https://images.unsplash.com/photo-1590080876-a371a6b6d7c5?w=500&h=400&fit=crop',
      price: 99,
      protein: 20,
      carbs: 22,
      fiber: 3,
      calories: 250,
      category: 'Salads',
    },
  ];

  useEffect(() => {
    const fetchMeals = async () => {
      try {
        const response = await getMeals();
        // If API returns array or { data: [] } adapt accordingly
        const apiMeals = Array.isArray(response) ? response : response.data || [];
        setMeals(apiMeals);
        setFilteredMeals(apiMeals);
      } catch (error) {
        console.error('Error fetching meals — using mock data:', error);
        // Fallback to mock data if API fails
        setMeals(mockMeals);
        setFilteredMeals(mockMeals);
      } finally {
        setLoading(false);
      }
    };

    fetchMeals();
  }, []);

  useEffect(() => {
    // Filtering — case-insensitive comparison
    let filtered = meals;

    if (selectedCategory !== 'All') {
      const sel = selectedCategory.toLowerCase();
      filtered = filtered.filter(meal => (meal.category || '').toLowerCase() === sel);
    }

    if (searchTerm) {
      const q = searchTerm.toLowerCase();
      filtered = filtered.filter(meal =>
        (meal.name || '').toLowerCase().includes(q) ||
        (meal.description || '').toLowerCase().includes(q)
      );
    }

    setFilteredMeals(filtered);
  }, [searchTerm, selectedCategory, meals]);

  return (
    <div className="min-h-screen bg-neutral-bg py-12 px-6">
      <div className="max-w-7xl mx-auto">
        {/* Header */}
        <motion.div
          initial={{ opacity: 0, y: -20 }}
          animate={{ opacity: 1, y: 0 }}
          className="mb-12"
        >
          <h1 className="text-4xl font-poppins font-bold text-dark-text mb-2">
            Our Menu
          </h1>
          <p className="text-gray-600">
            Choose from our wide selection of nutritious meals
          </p>
        </motion.div>

        {/* Search Bar */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.1 }}
          className="mb-8"
        >
          <div className="relative">
            <Search className="absolute left-4 top-1/2 transform -translate-y-1/2 text-gray-400" size={20} />
            <input
              type="text"
              placeholder="Search meals..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              className="w-full pl-12 pr-4 py-3 rounded-2xl border-2 border-gray-200 focus:border-primary focus:outline-none transition-colors"
            />
          </div>
        </motion.div>

        {/* Filters */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
          className="mb-12"
        >
          <div className="flex flex-wrap gap-3">
            {categories.map((category) => (
              <motion.button
                key={category}
                whileHover={{ scale: 1.05 }}
                whileTap={{ scale: 0.95 }}
                onClick={() => setSelectedCategory(category)}
                className={`px-6 py-2 rounded-full font-semibold transition-all duration-300 ${
                  selectedCategory === category
                    ? 'bg-primary text-white shadow-premium'
                    : 'bg-white text-dark-text border-2 border-gray-200 hover:border-primary'
                }`}
              >
                {category}
              </motion.button>
            ))}
          </div>
        </motion.div>

        {/* Meals Grid */}
        {loading ? (
          <div className="text-center py-12">
            <p className="text-gray-600">Loading meals...</p>
          </div>
        ) : filteredMeals.length > 0 ? (
          <motion.div
            className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6"
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            transition={{ duration: 0.5 }}
          >
            {filteredMeals.map((meal) => (
              <MealCard key={meal.id} meal={meal} />
            ))}
          </motion.div>
        ) : (
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            className="text-center py-12"
          >
            <p className="text-gray-600 text-lg">
              No meals found. Try adjusting your filters.
            </p>
          </motion.div>
        )}
      </div>
    </div>
  );
};

export default Menu;
